;s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:6:{s:2:\"id\";i:97;s:10:\"product_id\";i:97;s:6:\"locale\";s:2:\"en\";s:4:\"name\";s:18:\"Nan Optipro 1 800g\";s:11:\"description\";s:826:\"<p>Nan Optipro 1 800g is a premium infant formula designed for babies from birth to 6 months. Enriched with essential nutrients, DHA, and probiotics, it supports your baby&rsquo;s healthy growth, immune system, and brain development during the crucial first months of life.</p>\n<p>Formulated with probiotics, Nan Optipro 1 helps improve digestion and enhance nutrient absorption, ensuring your baby receives the full benefits of each feed. DHA (Omega-3 fatty acids) plays a critical role in the development of the brain and eyes, while calcium and iron promote strong bones and healthy blood.</p>\n<p>Trusted by parents and backed by Nestl&eacute;\'s expertise in infant nutrition, Nan Optipro 1 800g is the perfect complement to breastfeeding, providing a balanced, gentle, and nutritious feeding solution for your newborn.</p>\";s:17:\"short_description\";s:176:\"Nan Optipro 1 800g: Infant formula for babies from birth to 6 months, enriched with DHA, probiotics, and essential nutrients to support growth, immunity, and brain development.\";}s:11:\"\0*\0original\";a:6:{s:2:\"id\";i:97;s:10:\"product_id\";i:97;s:6:\"locale\";s:2:\"en\";s:4:\"name\";s:18:\"Nan Optipro 1 800g\";s:11:\"description\";s:826:\"<p>Nan Optipro 1 800g is a premium infant formula designed for babies from birth to 6 months. Enriched with essential nutrients, DHA, and probiotics, it supports your baby&rsquo;s healthy growth, immune system, and brain development during the crucial first months of life.</p>\n<p>Formulated with probiotics, Nan Optipro 1 helps improve digestion and enhance nutrient absorption, ensuring your baby receives the full benefits of each feed. DHA (Omega-3 fatty acids) plays a critical role in the development of the brain and eyes, while calcium and iron promote strong bones and healthy blood.</p>\n<p>Trusted by parents and backed by Nestl&eacute;\'s expertise in infant nutrition, Nan Optipro 1 800g is the perfect complement to breastfeeding, providing a balanced, gentle, and nutritious feeding solution for your newborn.</p>\";s:17:\"short_description\";s:176:\"Nan Optipro 1 800g: Infant formula for babies from birth to 6 months, enriched with DHA, probiotics, and essential nutrients to support growth, immunity, and brain development.\";}s:10:\"\0*\0changes\";a:0:{}s:8:\"\0*\0casts\";a:0:{}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:10:\"timestamps\";b:0;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:3:{i:0;s:4:\"name\";i:1;s:11:\"description\";i:2;s:17:\"short_description\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}}}s:28:\"\0*\0escapeWhenCastingToString\";b:0;}s:5:\"files\";O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:1:{i:0;O:27:\"Modules\\Media\\Entities\\File\":30:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"files\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:10:{s:2:\"id\";i:245;s:7:\"user_id\";i:1;s:8:\"filename\";s:81:\"nestle-nan-optipro-1-starter-infant-formula-powder-from-birth-800g-wBRoFXuCvs.jpg\";s:4:\"disk\";s:14:\"public_