(62, 36, 'en', 'Aptamil 4 Growing-Up Formula 800g | Probashi Bazar Banglades', 'Buy Aptamil 4 800g from Probashi Bazar – premium growing-up formula for toddlers 2+ years, supporting healthy growth and development.'),
(63, 34, 'en', 'Aptamil 3 Toddler Milk 800g – Nutritional Formula for 12–24 Months | Probashi Bazar', 'Aptamil 3 toddler milk (800g) for 12–24 months. Enriched with DHA, prebiotics, vitamins & minerals. Supports growth, brain & immune development.'),
(64, 134, 'en', 'Nestlé Lactogen 2 Follow-Up Formula Powder – 650g | Infant Nutrition', 'Buy Nestlé Lactogen 2 Follow-Up Formula Powder (650g) – specially designed for infants from 6 to 12 months. Supports healthy growth and easy digestion with essential nutrients.'),
(65, 135, 'en', 'Lactogen Probio 3 650g | Nutrition for Growing Toddlers | Nestlé', 'Nestlé Lactogen Probio 3 650g is formulated with probiotics, vitamins, and minerals to support healthy growth, digestion, and immunity in toddlers aged 1–3 years.'),
(66, 136, 'en', 'Lactogen 1 650g | Infant Formula for Newborns | Nestlé', 'Nestlé Lactogen 1 650g is an infant formula for newborns, enriched with essential nutrients to support healthy growth, immunity, and development during the first months of life.'),
(67, 137, 'en', 'Nan Optipro 3 800g | Toddler Milk Formula for Growth & Immunity | Nestlé', 'Nan Optipro 3 800g is a toddler milk formula from Nestlé, enriched with essential nutrients and probiotics to support healthy growth, immunity, and brain development for children aged 1–3 years.'),
(68, 138, 'en', 'Nan Optipro 2 800g | Advanced Infant Formula for Healthy Growth & Immunity | Nestlé', 'Nan Optipro 2 800g is an advanced infant formula from Nestlé, designed for babies aged 6–12 months. Enriched with essential nutrients, probiotics, and DHA to support healthy growth, immunity, and brain development.'),
(69, 139, 'en', 'Nan Optipro 1 800g | Premium Infant Formula for Healthy Growth & Immunity | Nestlé', 'Nan Optipro 1 800g is a premium infant formula from Nestlé, designed for babies from birth to 6 months. Enriched with essential nutrients, DHA, and probiotics to support healthy growth, immunity, and brain development.'),
(70, 140, 'en', 'Nan Optipro 4 800g | Toddler Milk Formula for Growth, Immunity & Brain Development | Nestlé', 'Nan Optipro 4 800g is a toddler milk formula from Nestlé, designed for children aged 3+ years. Enriched with essential nutrients, DHA, and probiotics to support healthy growth, immunity, and brain development.'),
