INSERT INTO `product_translations` (`id`, `product_id`, `locale`, `name`, `description`, `short_description`) VALUES
(1, 1, 'en', 'Lactogen 1', '<p>Baby milk 1800g</p>', NULL),
(2, 2, 'en', 'Lactozen', '<p>Lactozen</p>', 'short'),
(3, 3, 'en', 'Nestle Lactogen 2', '<p>It is good</p>', NULL),
(4, 4, 'en', 'Nestle Lactogen 3', '<p>It is good</p>', NULL),
(5, 5, 'en', 'Nestle Lactogen 1', '<blockquote>\n<p>&nbsp;</p>\n</blockquote>', 'Product Name: Lactogen 1 - 1800g\n\nAge Group:\n\nSuitable for infants from 6 months to 12 months \n\nKey Benefits:\n\nComplete Nutrition: Provides essential nutrients for healthy growth and development.\n\nSupports Digestion: Easy-to-digest formula to keep your baby comfortable.\n\nImmune Support: Contains vitamins and minerals to help strengthen the baby’s immune system.\n\nBrain Development: Specially designed to support cognitive development with DHA and other key nutrients.\n\nFeatures:\n\n1800g Size: A larger pack, ideal for long-term use and value for money.\n\nBreast Milk Substitute: When breastfeeding is not an option, Lactogen 1 serves as a reliable substitute.\n\nTrusted Brand: A formula developed by Nestlé, trusted by mothers worldwide.\n\n\nDirections for Use:\n\n1. Boil clean water and let it cool to lukewarm.\n\n2. Measure the exact amount of water as per the instructions.\n\n3. Add the required number of scoops of Lactogen 1.\n\n4. Stir until the powder is completely dissolved.\n\n5. Feed immediately and discard any leftover milk.\n\nStorage Instructions:\n\nKeep the product in a cool, dry place.\n\nAfter opening, use within 3 weeks. Close the can tightly after each use.'),
(6, 6, 'en', 'Aptamil 1 Infant Formula 800g', '<p>Aptamil 1 Infant Formula 800g &ndash; Probashi Bazar</p>\n<p>Give your newborn the best start with Aptamil 1 800g, specially formulated for babies 0&ndash;6 months. Enriched with vitamins, minerals, DHA, and prebiotics, it supports healthy growth, immunity, and brain development.</p>\n<p>Available at Probashi Bazar, this premium infant formula is gentle on tummies and closely mimics the nutrition of mother&rsquo;s milk. Trusted by parents worldwide, Aptamil 1 ensures your baby gets complete, safe, and balanced nutrition.</p>\n<p>Why choose Aptamil 1 from Probashi Bazar?</p>\n<p>Complete nutrition for infants 0&ndash;6 months</p>\n<p>Supports immunity and cognitive development</p>\n<p>Easy to prepare and safe</p>\n<p>Original imported product delivered in Bangladesh</p>\n<p><br />Order now from Probashi Bazar and give your baby the premium care they deserve.</p>', 'Give your baby the best start with Aptamil 1 800g from Probashi Bazar – complete nutrition for early growth.'),
(7, 7, 'en', 'Aptamil 3 Growing-Up Milk 800g – Probashi Bazar', '<p>Aptamil Stage 3 is a scientifically formulated toddler milk designed for children aged 12 months and older. With over 50 years of breastmilk research behind it, this formula includes a unique blend of GOS/FOS prebiotics, 3&prime;‑GL, Omega‑3 (ALA &amp; DHA), and Omega‑6, along with essential vitamins (A, C, D, E, K, B‑complex) and minerals (calcium, iron, iodine, zinc). It supports immune health, brain development, bone growth, digestion, and overall well-being. Critically, it is free from palm oil, artificial colors, and preservatives&nbsp;&nbsp;</p>', 'Aptamil 3 (800g) – Toddler formula for 12–24 months with prebiotics, DHA, and key nutrients to support growth and immunity. Palm oil–free.'),
(8, 8, 'en', 'Aptamil 2 Follow-On Milk 800g – Probashi Bazar', '<p>Aptamil 2 Follow-On Formula 800g &ndash; Probashi Bazar</p>\n<p>Give your baby the best nutrition with Aptamil 2 800g, specially formulated for infants 6&ndash;12 months. Enriched with DHA, vitamins, minerals, and prebiotics, it supports healthy growth, strong immunity, and brain development.</p>\n<p>Available at Probashi Bazar, this premium follow-on formula is gentle on your baby&rsquo;s tummy and closely mimics the nutrition of mother&rsquo;s milk, ensuring your child receives complete, safe, and balanced nutrition.</p>\n<p>Why choose Aptamil 2 from Probashi Bazar?</p>\n<p>Complete nutrition for 6&ndash;12 month babies</p>\n<p>Supports immunity and cognitive growth</p>\n<p>Easy to prepare and safe</p>\n<p>Guaranteed original imported product</p>\n<p><br />Order Aptamil 2 800g from Probashi Bazar today and provide your baby with premium care for a healthy start.</p>', 'Buy Aptamil 2 800g from Probashi Bazar – follow-on formula for babies 6–12 months, supporting healthy growth, immunity, and brain development.Aptamil 2 Follow-On Formula 800g – Probashi Bazar\n\nGive your baby the best nutrition with Aptamil 2 800g, specially formulated for infants 6–12 months. Enriched with DHA, vitamins, minerals, and prebiotics, it supports healthy growth, strong immunity, and brain development.\n\nAvailable at Probashi Bazar, this premium follow-on formula is gentle on your baby’s tummy and closely mimics the nutrition of mother’s milk, ensuring your child receives complete, safe, and balanced nutrition.\n\nWhy choose Aptamil 2 from Probashi Bazar?\n\nComplete nutrition for 6–12 month babies\n\nSupports immunity and cognitive growth\n\nEasy to prepare and safe\n\nGuaranteed original imported product\n\n\nOrder Aptamil 2 800g from Probashi Bazar today and provide your baby with premium care for a healthy start.'),
(9, 9, 'en', 'Aptamil 4 Toddler Milk 800g – Probashi Bazar', '<p>Aptamil 4 Growing-Up Milk is specially formulated to support your toddler\'s nutritional needs from 2 years and above. Inspired by 50 years of breast milk research, it contains a unique blend of GOS/FOS prebiotics and essential nutrients to help support normal immune function, cognitive development, and healthy growth. Ideal as part of a balanced diet during early childhood, Aptamil 4 is free from palm oil and designed to complement everyday family meals.</p>\n<p>&nbsp;</p>', 'Aptamil 4 800g at Probashi Bazar – nutritious growing-up milk for toddlers 2+ years, supporting strong growth, immunity, and development.'),
(10, 10, 'en', 'Cow & Gate 1', '<p>Good</p>', NULL),
(11, 11, 'en', 'Cow & Gate 2', '<p>Good for baby</p>', NULL),
(12, 12, 'en', 'Cow & Gate', '<p>Good for baby</p>', NULL),
(13, 13, 'en', 'Cow & Gate 4', '<p>Good for toddler</p>', NULL),
